// src/components/Sidebar.js
import React from 'react';
import { NavLink } from 'react-router-dom';

const Sidebar = ({ onLogout }) => {
  const navItems = [
    { 
      path: '/', 
      name: 'Dashboard', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z" />
        </svg>
      ),
      badge: null
    },
    { 
      path: '/live-tracking', 
      name: 'Live Tracking', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
        </svg>
      ),
      badge: "3"
    },
    { 
      path: '/route-optimization', 
      name: 'Route Optimization', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" />
        </svg>
      ),
      badge: null
    },
    { 
      path: '/traffic-layer', 
      name: 'Traffic Layer', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z" />
        </svg>
      ),
      badge: null
    },
    { 
      path: '/notifications', 
      name: 'Notifications', 
      icon: (
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 17h5l-5 5v-5zM11 19l-7-7 7-7m0 14l9-9" />
        </svg>
      ),
      badge: "7"
    },
  ];

  return (
    <div className="h-full flex flex-col relative overflow-hidden">
      {/* ✅ Navy Gradient Background */}
      <div className="absolute inset-0 bg-gradient-to-br from-slate-900 via-blue-900 to-slate-800"></div>
      
      {/* ✅ Glass Morphism Overlay */}
      <div className="absolute inset-0 bg-gradient-to-br from-blue-900/20 via-transparent to-slate-900/30 backdrop-blur-sm"></div>
      
      {/* Content */}
      <div className="relative z-10 h-full flex flex-col">
        
        {/* ✅ Modern Header */}
        <div className="p-6 border-b border-white/10">
          <div className="flex items-center">
            {/* ✅ Modern Logo with Gradient */}
            <div className="w-10 h-10 bg-gradient-to-br from-blue-400 to-cyan-400 rounded-xl flex items-center justify-center mr-3 shadow-lg shadow-blue-500/25">
              <span className="text-white font-bold text-lg">NF</span>
            </div>
            {/* ✅ Brand Name */}
            <div>
              <h1 className="text-white font-bold text-lg">NeuroFleetX</h1>
              <p className="text-blue-200 text-xs opacity-80">Fleet Management</p>
            </div>
          </div>
        </div>

        {/* ✅ Modern Navigation */}
        <nav className="flex-1 px-4 py-6">
          <ul className="space-y-2">
            {navItems.map((item) => (
              <li key={item.path}>
                <NavLink
                  to={item.path}
                  className={({ isActive }) =>
                    `group flex items-center px-4 py-3 text-sm font-medium rounded-xl transition-all duration-300 relative overflow-hidden ${
                      isActive
                        ? 'text-white bg-gradient-to-r from-blue-500/30 to-cyan-500/20 shadow-lg shadow-blue-500/20 border border-blue-400/30'
                        : 'text-blue-100 hover:text-white hover:bg-white/10 backdrop-blur-sm'
                    }`
                  }
                >
                  {/* ✅ Hover Background Effect */}
                  <div className="absolute inset-0 bg-gradient-to-r from-blue-500/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                  
                  {/* ✅ Modern SVG Icons */}
                  <div className="mr-3 flex-shrink-0 relative z-10">
                    {item.icon}
                  </div>
                  
                  {/* ✅ Menu Text */}
                  <span className="truncate relative z-10 flex-1">{item.name}</span>
                  
                  {/* ✅ Notification Badges */}
                  {item.badge && (
                    <div className="ml-auto relative z-10">
                      <span className="inline-flex items-center justify-center w-5 h-5 text-xs font-bold text-white bg-gradient-to-r from-red-500 to-pink-500 rounded-full shadow-lg animate-pulse">
                        {item.badge}
                      </span>
                    </div>
                  )}
                  
                  {/* ✅ Glow Effect */}
                  <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-blue-400/0 via-blue-400/5 to-cyan-400/0 opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                </NavLink>
              </li>
            ))}
          </ul>
        </nav>

        {/* ✅ Modern User Section */}
        <div className="p-4 border-t border-white/10">
          <div className="bg-white/5 backdrop-blur-sm rounded-xl p-4 border border-white/10">
            {/* User Info */}
            <div className="flex items-center mb-4">
              <div className="w-10 h-10 bg-gradient-to-br from-blue-400 to-cyan-400 rounded-full flex items-center justify-center mr-3 shadow-lg">
                <span className="text-white font-semibold text-sm">R</span>
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-white font-medium text-sm truncate">Rakasri</p>
                <p className="text-blue-200 text-xs opacity-80">Fleet Manager</p>
              </div>
            </div>

            {/* ✅ Status Indicator */}
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center">
                <div className="w-2 h-2 bg-green-400 rounded-full mr-2 animate-pulse"></div>
                <span className="text-green-300 text-xs font-medium">Online</span>
              </div>
              <span className="text-blue-200 text-xs">Active Session</span>
            </div>

            {/* ✅ Action Buttons */}
            <div className="flex space-x-2">
              <button className="flex-1 bg-white/10 hover:bg-white/20 text-white text-xs font-medium py-2 px-3 rounded-lg transition-colors duration-200 backdrop-blur-sm">
                Profile
              </button>
              <button
                onClick={onLogout}
                className="flex-1 bg-red-500/20 hover:bg-red-500/30 text-red-200 hover:text-white text-xs font-medium py-2 px-3 rounded-lg transition-all duration-200 border border-red-400/30"
              >
                Logout
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;
